(() => {
    const canvas = document.getElementById("fireworks");
    if (!canvas || typeof anime === "undefined") return;

    const ctx = canvas.getContext("2d");
    const animations = [];
    const colors = ["#ff324a", "#31ffa6", "#206eff", "#ffff99"];
    let pointerDown = null;

    function fontSize() {
        return parseFloat(getComputedStyle(document.documentElement).fontSize);
    }

    function resizeCanvas() {
        const scale = window.devicePixelRatio || 1;
        canvas.width = window.innerWidth * scale;
        canvas.height = window.innerHeight * scale;
        ctx.setTransform(scale, 0, 0, scale, 0, 0);
    }

    function removeAnimation(animation) {
        const index = animations.indexOf(animation);
        if (index > -1) animations.splice(index, 1);
    }

    function hasTextSelection() {
        const selection = window.getSelection && window.getSelection();
        return !!selection && !selection.isCollapsed && selection.toString().trim().length > 0;
    }

    function createParticle(x, y) {
        return {
            x,
            y,
            color: colors[anime.random(0, colors.length - 1)],
            radius: anime.random(fontSize(), fontSize() * 2),
            draw() {
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.radius, 0, 2 * Math.PI, true);
                ctx.fillStyle = this.color;
                ctx.fill();
            },
        };
    }

    function createCircle(x, y) {
        return {
            x,
            y,
            color: "#fff",
            radius: 0,
            alpha: 1,
            lineWidth: 6,
            draw() {
                ctx.globalAlpha = this.alpha;
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.radius, 0, 2 * Math.PI, true);
                ctx.lineWidth = this.lineWidth;
                ctx.strokeStyle = this.color;
                ctx.stroke();
                ctx.globalAlpha = 1;
            },
        };
    }

    function firework(x, y) {
        resizeCanvas();

        const particles = [];
        for (let i = 0; i < 24; i++) particles.push(createParticle(x, y));
        const circle = createCircle(x, y);

        const particleAnimation = anime({
            targets: particles,
            x: (particle) => particle.x + anime.random(-200, 200),
            y: (particle) => particle.y + anime.random(-200, 200),
            radius: 0,
            duration: () => anime.random(1200, 1800),
            easing: "easeOutExpo",
            complete: removeAnimation,
        });

        const circleAnimation = anime({
            targets: circle,
            radius: () => anime.random(fontSize() * 8.75, fontSize() * 11.25),
            lineWidth: 0,
            alpha: {
                value: 0,
                easing: "linear",
                duration: () => anime.random(400, 600),
            },
            duration: () => anime.random(1200, 1800),
            easing: "easeOutExpo",
            complete: removeAnimation,
        });

        animations.push(particleAnimation, circleAnimation);
    }

    resizeCanvas();

    anime({
        duration: Infinity,
        update() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            animations.forEach((animation) => {
                animation.animatables.forEach((animatable) => animatable.target.draw());
            });
        },
    });

    document.addEventListener(
        "mousedown",
        (event) => {
            if (event.button !== 0) return;
            pointerDown = {
                x: event.clientX,
                y: event.clientY,
                hadSelection: hasTextSelection(),
            };
        },
        false
    );

    document.addEventListener(
        "mouseup",
        (event) => {
            if (!pointerDown || event.button !== 0) return;
            const moved = Math.hypot(event.clientX - pointerDown.x, event.clientY - pointerDown.y);
            const selectingText = hasTextSelection() && (moved > 3 || !pointerDown.hadSelection);
            const point = pointerDown;
            pointerDown = null;
            if (selectingText) return;
            firework(point.x, point.y);
        },
        false
    );

    window.addEventListener("resize", resizeCanvas, false);
})();
